接续在 memory.py 中 ArchivalMemory 后新增：

```python
class WorkingMemory:
    """工作记忆：当前会话上下文缓存。

    临时存储当前会话的数据（对话轮次、DSL 中间状态、MAPE-K 信号）。
    短生命周期：会话结束时或达到容量上限时自动清理。
    """

    def __init__(self, capacity: int = 50):
        self._store: dict[str, list[dict]] = {}
        self._capacity = capacity

    def set(self, key: str, value: Any) -> None:
        """写入当前工作记忆。"""
        if key not in self._store:
            self._store[key] = []
        self._store[key].append({
            "value": value,
            "timestamp": self._now_utc(),
        })
        # 超容量裁剪
        if len(self._store[key]) > self._capacity:
            self._store[key] = self._store[key][-self._capacity:]

    def get(self, key: str, default: Any = None) -> Any:
        """读取最近的工作记忆值。"""
        items = self._store.get(key, [])
        if not items:
            return default
        return items[-1]["value"]

    def get_all(self, key: str) -> list[dict]:
        """读取指定 key 的所有历史值。"""
        return list(self._store.get(key, []))

    def clear(self) -> None:
        """清空所有工作记忆。"""
        self._store.clear()

    def keys(self) -> list[str]:
        return list(self._store.keys())

    def size(self) -> int:
        return sum(len(v) for v in self._store.values())

    def _now_utc(self) -> str:
        from datetime import datetime, timezone
        return datetime.now(timezone.utc).strftime(
            '%Y-%m-%dT%H:%M:%S.%f')[:-3] + 'Z'
```
